+      expect(result.success).toBe(true);
+      expect(result.data).toEqual({
+        totalOrders: 0,
+        totalRevenue: 0,
+        averageOrderValue: 0,
+        minOrderValue: 0,
+        maxOrderValue: 0,
+      });
+    });
+
+    it('should reflect orders created through the service layer', async () => {
+      const user = await createUser('Alice', 'alice@test.com');
+      await createOrderForUser(user.id, [
+        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 25 },
+      ]);
+      await createOrderForUser(user.id, [
+        { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 100 },
+      ]);
+
+      const result = routes.getOrderSummary();
+      expect(result.success).toBe(true);
+      expect(result.data!.totalOrders).toBe(2);
+      expect(result.data!.totalRevenue).toBe(150); // 50 + 100
+      expect(result.data!.averageOrderValue).toBe(75);
+      expect(result.data!.minOrderValue).toBe(50);
+      expect(result.data!.maxOrderValue).toBe(100);
+    });
+
+    it('should include orders from multiple users', async () => {
+      const alice = await createUser('Alice', 'alice@test.com');
+      const bob = await createUser('Bob', 'bob@test.com');
+
+      await createOrderForUser(alice.id, [
+        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 30 },
+      ]);
+      await createOrderForUser(bob.id, [
+        { productId: 'p2', name: 'Gadget', quantity: 3, unitPrice: 20 },
