/**
 * Integration tests for the full analytics pipeline.
 *
 * Tests the complete flow: UserService → OrderService → AggregationService → AnalyticsRoutes.
 * All layers use real implementations (no mocks) wired to a fresh in-memory database.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserService, resetUserIdCounter } from '../../src/services/user.service.js';
import { OrderService, resetOrderIdCounter } from '../../src/services/order.service.js';
import { AggregationService } from '../../src/services/aggregation.service.js';
import { AnalyticsRoutes } from '../../src/routes/analytics.routes.js';
import { EventBus } from '../../src/events/event-bus.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

describe('Analytics Pipeline Integration', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let eventBus: EventBus;
  let userService: UserService;
  let orderService: OrderService;
  let aggregationService: AggregationService;
  let routes: AnalyticsRoutes;

  beforeEach(() => {
    // Reset all shared state
    resetUserIdCounter();
    resetOrderIdCounter();
    statusChangeCallbacks.clear();

    // Wire the full stack
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    eventBus = new EventBus();
    userService = new UserService(userRepo, eventBus);
    orderService = new OrderService(orderRepo, userRepo, eventBus);
    aggregationService = new AggregationService(orderRepo);
    routes = new AnalyticsRoutes(aggregationService);
  });

  // ── Helpers ──────────────────────────────────────────────────

  async function createUser(name: string, email: string, role: User['role'] = 'member'): Promise<User> {
    return userService.createUser({ name, email, role });
  }

  async function createOrderForUser(
    userId: string,
    items: { productId: string; name: string; quantity: number; unitPrice: number }[],
  ): Promise<Order> {
    return orderService.createOrder({ userId, items });
  }

  // ── Dashboard data (order summary) ──────────────────────────

  describe('Dashboard: Order Summary', () => {
    it('should return zeros when no orders exist', () => {
      const result = routes.getOrderSummary();
      expect(result.success).toBe(true);
